#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>

template<typename T>
__device__ void warp_reduce_sum(float& val) {
    #if __CUDA_ARCH__ >= 300
    for (int offset = 16; offset > 0; offset >>= 1) {
        val += __shfl_down_sync(0xffffffff, val, offset);
    }
    #else
    __shared__ float warp_shuffle[32];
    int lane = threadIdx.x % 32;
    int warp_id = threadIdx.x / 32;
    if (lane == 0) {
        warp_shuffle[warp_id] = val;
    }
    __syncthreads();
    if (warp_id == 0) {
        val = warp_shuffle[lane];
    }
    #endif
}

template<typename T>
__global__ void instance_norm_forward_kernel(
    const T* input,
    T* output,
    const int batch_size,
    const int num_features,
    const int height,
    const int width,
    const float eps
) {
    const int feature_idx = blockIdx.x;
    const int batch_idx = blockIdx.y;
    const int tid = threadIdx.x;

    const int spatial_size = height * width;
    const int feature_offset = feature_idx * spatial_size;
    const int batch_offset = batch_idx * num_features * spatial_size;
    const int start_idx = batch_offset + feature_offset;

    // Shared memory for reduction
    __shared__ float shared_sum[256];
    __shared__ float shared_sq_sum[256];

    // First pass: compute mean
    float sum = 0.0f;
    for (int i = tid; i < spatial_size; i += blockDim.x) {
        int idx = start_idx + i;
        sum += static_cast<float>(input[idx]);
    }

    // Warp-level reduction
    warp_reduce_sum<T>(sum);

    // Store warp results in shared memory
    if (threadIdx.x % 32 == 0) {
        shared_sum[threadIdx.x / 32] = sum;
    }
    __syncthreads();

    // Final reduction across warps using only first warp
    if (threadIdx.x < 8) {  // 256 threads / 32 = 8 warps
        float warp_sum = (threadIdx.x < blockDim.x/32) ? shared_sum[threadIdx.x] : 0.0f;
        warp_reduce_sum<T>(warp_sum);
        if (threadIdx.x == 0) {
            shared_sum[0] = warp_sum;
        }
    }
    __syncthreads();

    float mean = shared_sum[0] / spatial_size;
    __syncthreads();

    // Second pass: compute variance
    float sq_sum = 0.0f;
    for (int i = tid; i < spatial_size; i += blockDim.x) {
        int idx = start_idx + i;
        float diff = static_cast<float>(input[idx]) - mean;
        sq_sum += diff * diff;
    }

    // Warp-level reduction for variance
    warp_reduce_sum<T>(sq_sum);

    // Store warp results in shared memory
    if (threadIdx.x % 32 == 0) {
        shared_sq_sum[threadIdx.x / 32] = sq_sum;
    }
    __syncthreads();

    // Final reduction across warps using only first warp
    if (threadIdx.x < 8) {
        float warp_sq_sum = (threadIdx.x < blockDim.x/32) ? shared_sq_sum[threadIdx.x] : 0.0f;
        warp_reduce_sum<T>(warp_sq_sum);
        if (threadIdx.x == 0) {
            shared_sq_sum[0] = warp_sq_sum;
        }
    }
    __syncthreads();

    float variance = shared_sq_sum[0] / spatial_size;
    float inv_std = rsqrtf(variance + eps);

    // Third pass: normalize
    for (int i = tid; i < spatial_size; i += blockDim.x) {
        int idx = start_idx + i;
        float normalized = (static_cast<float>(input[idx]) - mean) * inv_std;
        output[idx] = static_cast<T>(normalized);
    }
}

